}

Method.Source:
public static ITMTmpCreatorLine createOnServerOutboundETG()
{
    ITMTmpCreatorLine tmpShipCreatorLine;

    select tmpShipCreatorLine;

    return tmpShipCreatorLine;
}

/// <summary>
/// transfer qty validation for sales and transfer order
/// </summary>
/// <returns>boolean</returns>
public boolean checkTransferQty()
{
    boolean ret = true;

    if (ret 
        && ITMParameters::find().ETGEnableLandedCostOutboundOrder == NoYes::Yes
        && (this.InventTransType == InventTransType::Sales || this.InventTransType == InventTransType::TransferOrderShip)
        && this.TransferQty > this.InventQty)
    {
        throw error(strFmt("@ETG_New:LandedCostOutTransferQtyError", this.TransferQty, this.InventQty));
    }

    ret = next checkTransferQty();

    return ret;
}
